{
  "mitigation_currently_implemented": "Enable Fail2Ban on UbuntuComputer to monitor logs and ban IP addresses exhibiting scanning or brute force behavior",
  "comments": "Configured and enabled Fail2Ban on the UbuntuComputer to monitor system logs and ban IP addresses exhibiting suspicious activities like scanning or brute force attempts. This is a host-based mitigation suitable for the current environment where package installation and proxies are not feasible. Fail2Ban helps to dynamically block malicious IPs and reduce attack success while the attacker remains in the network.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "fail2ban-client status",
    "echo -e \"[sshd]\\nenabled = true\\nport = ssh\\nfilter = sshd\\nlogpath = /var/log/auth.log\\nmaxretry = 3\" > /etc/fail2ban/jail.d/sshd.local",
    "service fail2ban restart"
  ]
}
